const toStr = (v) => String(v ?? '').trim();
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const getEnv = (key) => {
  try {
    if ($env && $env[key]) return String($env[key]).trim();
  } catch (_e) {}
  try {
    const p = (typeof globalThis !== 'undefined' && globalThis.process && globalThis.process.env)
      ? globalThis.process.env[key]
      : '';
    if (p) return String(p).trim();
  } catch (_e) {}
  return '';
};

const getStore = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (this && typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  throw new Error('[Normalize Chat Input] static data indisponivel no Code node.');
};

const raw = $json || {};
const message = toStr(raw.chatInput || raw.message || raw.text || raw.input || '');
const sessionId = toStr(raw.sessionId || raw.session_id || raw.chatSessionId || raw.metadata?.sessionId || 'default');

const store = getStore();
if (!store.chatMemory) store.chatMemory = {};
if (!Array.isArray(store.chatMemory[sessionId])) store.chatMemory[sessionId] = [];
if (!store.selectedOption) store.selectedOption = {};
if (!store.impactIntakeState) store.impactIntakeState = {};

const pushMemory = (role, content) => {
  const text = toStr(content);
  if (!text) return;
  store.chatMemory[sessionId].push({ role, content: text, at: new Date().toISOString() });
  if (store.chatMemory[sessionId].length > 40) {
    store.chatMemory[sessionId] = store.chatMemory[sessionId].slice(-40);
  }
};

const chatHistory = () => store.chatMemory[sessionId]
  .slice(-12)
  .map((t) => ({ role: t.role, content: toStr(t.content) }));

const menuText = [
  'Escolha uma opcao para continuar (envie apenas 1, 2 ou 3):',
  '1) Nova analise de Impacto',
  '2) Duvida sobre funcionalidade ja implementada',
  '3) Correcao de PRs abertas'
].join('\n');

const invalidOutput = 'opção inválida! Escolha 1,2 ou 3';

if (!message) {
  return [{
    json: {
      option: 'invalid',
      route: 'impact_collect_question',
      session_id: sessionId,
      chat_history: chatHistory(),
      output: menuText,
    }
  }];
}

const lower = norm(message);
if (lower === '/reset') {
  delete store.selectedOption[sessionId];
  delete store.impactIntakeState[sessionId];
  return [{
    json: {
      option: 'invalid',
      route: 'impact_collect_question',
      session_id: sessionId,
      chat_history: chatHistory(),
      output: menuText,
    }
  }];
}

if (lower === '/menu') {
  return [{
    json: {
      option: 'invalid',
      route: 'impact_collect_question',
      session_id: sessionId,
      chat_history: chatHistory(),
      output: menuText,
    }
  }];
}

pushMemory('user', message);

const isOption = /^(1|2|3)$/.test(lower);
if (isOption) {
  const option = lower;
  store.selectedOption[sessionId] = option;

  if (option === '1') {
    const currentState = store.impactIntakeState[sessionId] || {
      problema: '',
      mudanca: '',
      evidencias: '',
      restricoes: '',
      status: '',
      diagnostico: '',
      evidencias_lista: []
    };
    store.impactIntakeState[sessionId] = currentState;

    return [{
      json: {
        option: '1',
        route: 'impact_intake',
        is_selection: true,
        session_id: sessionId,
        chat_history: chatHistory(),
        user_message: message,
        question: message,
        impact_intake_state: currentState,
      }
    }];
  }

  if (option === '2') {
    return [{
      json: {
        option: '2',
        route: 'pr_qa',
        is_selection: true,
        session_id: sessionId,
        chat_history: chatHistory(),
        output: 'Opcao 2 selecionada. Agora descreva sua duvida sobre funcionalidade ja implementada.',
      }
    }];
  }

  return [{
    json: {
      option: '3',
      route: 'correction_propose',
      is_selection: true,
      session_id: sessionId,
      chat_history: chatHistory(),
      output: 'Opcao 3 selecionada. Agora descreva a correcao desejada nas PRs abertas.',
    }
  }];
}

const selected = toStr(store.selectedOption[sessionId]);
if (!selected) {
  return [{
    json: {
      option: 'invalid',
      route: 'impact_collect_question',
      session_id: sessionId,
      chat_history: chatHistory(),
      output: invalidOutput + '\n\n' + menuText,
    }
  }];
}

if (selected === '1') {
  const currentState = store.impactIntakeState[sessionId] || {
    problema: '',
    mudanca: '',
    evidencias: '',
    restricoes: '',
    status: '',
    diagnostico: '',
    evidencias_lista: []
  };

  return [{
    json: {
      option: '1',
      route: 'impact_intake',
      is_selection: false,
      session_id: sessionId,
      chat_history: chatHistory(),
      user_message: message,
      question: message,
      impact_intake_state: currentState,
    }
  }];
}

if (selected === '2') {
  return [{
    json: {
      option: '2',
      route: 'pr_qa',
      is_selection: false,
      session_id: sessionId,
      chat_history: chatHistory(),
