    session_id: req.session_id || 'default',
    chat_history: Array.isArray(req.chat_history) ? req.chat_history : [],
    question,
    owner,
    pr_context: {
      owner,
      repos,
      total_found: allPrs.length,
      selected_count: selected.length,
      query_terms: queryTerms,
      prs: selected,
      commit_text_hits: commitHits,
      code_snippets: codeSnippets,
      fastroute_modelo_dados: fastrouteModeloDados
    }
  }
}];

messageValues.message:
Voce e um arquiteto de mudancas e deve propor uma correcao a partir de PRs/codigo/commits existentes.
Considere tambem o modelo de dados do FastRoute presente no contexto.

Retorne SOMENTE JSON valido sem markdown, no formato:
{
  "status": "SIM|PARCIAL|NAO|SEM_EVIDENCIA",
  "diagnostico": "string",
  "impact_payload": {
    "problema": "string",
    "mudanca": "string",
    "evidencias": "string",
    "restricoes": "string"
  },
  "evidencias": [
    { "repo": "string", "pr_number": number, "url": "string", "arquivos": ["string"], "commits": ["string"] }
  ]
}

Regras:
1) impact_payload deve ser preenchido para acionar Impact Analysis.
2) Se faltar evidencia, use status=SEM_EVIDENCIA e descreva lacunas em diagnostico.
3) Nao invente PRs/arquivos/commits.

