    const governanceLike = title.toLowerCase().includes('governance: impact analysis') || headRef.startsWith('codex/governance-');
    if (!governanceLike) continue;

    allPrs.push({
      repo,
      number: pr.number,
      title,
      state: pr.state,
      draft: !!pr.draft,
      created_at: pr.created_at,
      updated_at: pr.updated_at,
      merged_at: pr.merged_at,
      user: toStr(pr.user?.login || ''),
      url: toStr(pr.html_url || ''),
      body: toStr(pr.body || '').slice(0, 7000),
      head: toStr(pr.head?.ref || ''),
      base: toStr(pr.base?.ref || '')
    });
  }
}

allPrs.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
const selected = allPrs.slice(0, 25);

const fileIndex = [];
const commitHits = [];
for (const pr of selected) {
  try {
    const files = await gh('https://api.github.com/repos/' + owner + '/' + pr.repo + '/pulls/' + pr.number + '/files?per_page=100');
    pr.files = (Array.isArray(files) ? files : []).map((f) => ({
      filename: toStr(f.filename),
      status: toStr(f.status),
      additions: toNum(f.additions) || 0,
      deletions: toNum(f.deletions) || 0,
      raw_url: toStr(f.raw_url || ''),
      blob_url: toStr(f.blob_url || '')
    }));

    for (const f of pr.files) {
      fileIndex.push({
        repo: pr.repo,
        pr_number: pr.number,
        filename: f.filename,
        raw_url: f.raw_url,
        blob_url: f.blob_url,
        pr_url: pr.url,
      });
    }
  } catch (_e) {
    pr.files = [];
  }

  try {
    const commits = await gh('https://api.github.com/repos/' + owner + '/' + pr.repo + '/pulls/' + pr.number + '/commits?per_page=100');
    pr.commits = (Array.isArray(commits) ? commits : []).map((c) => {
      const msg = toStr(c?.commit?.message || '');
      return {
        sha: toStr(c?.sha || '').slice(0, 10),
        message: msg.slice(0, 900),
        author: toStr(c?.commit?.author?.name || c?.author?.login || ''),
      };
    });

    if (queryTerms.length > 0) {
      const text = pr.commits.map((c) => c.message).join(' \n ').toLowerCase();
      const matched = queryTerms.filter((t) => text.includes(t));
      if (matched.length > 0) {
        commitHits.push({
          repo: pr.repo,
          pr_number: pr.number,
          url: pr.url,
          matched_terms: [...new Set(matched)],
          commit_messages: pr.commits.map((c) => c.message).slice(0, 10),
        });
      }
    }
  } catch (_e) {
    pr.commits = [];
  }
}

const matches = fileIndex.filter((f) => {
  if (queryTerms.length === 0) return false;
  const hay = (f.filename + ' ' + f.blob_url).toLowerCase();
  return queryTerms.some((t) => hay.includes(t));
}).slice(0, 20);

const codeSnippets = [];
for (const m of matches) {
  try {
    const content = await gh('https://api.github.com/repos/' + owner + '/' + m.repo + '/contents/' + encodePath(m.filename) + '?ref=main');
    let decoded = '';
    if (content && content.content) {
      decoded = Buffer.from(String(content.content).replace(/\n/g, ''), 'base64').toString('utf8');
    }
    codeSnippets.push({
      repo: m.repo,
      pr_number: m.pr_number,
      filename: m.filename,
      pr_url: m.pr_url,
      code: toStr(decoded).slice(0, 2500)
    });
  } catch (_e) {
    // ignore fetch errors
  }
}

const fastrouteModeloDados = {
  fonte: 'skill:fastroute/references/modelo-dados.md',
  tabelas_chave: [
    'orders', 'addresses', 'routes', 'route_waypoints', 'waypoint_delivery_photo',
    'change_log', 'mutations_applied', 'users', 'clients', 'orders_import'
  ],
  relacionamentos_relevantes: [
    'addresses.order_id -> orders.id',
    'routes.import_id -> orders_import.id',
    'routes.driver_id -> users.id',
    'orders.import_id -> orders_import.id'
  ],
  pontos_atencao: [
    'route_waypoints e routes usam status/version para ciclo de entrega',
    'change_log e mutations_applied suportam trilha e idempotencia offline-first',
    'dados de latitude/longitude aparecem em ordens e enderecos e impactam clustering/roteirizacao',
    'fotos de comprovacao em waypoint_delivery_photo vinculam rota, waypoint e usuario'
  ]
};

return [{
  json: {
    route: req.route,
    session_id: req.session_id || 'default',
    chat_history: Array.isArray(req.chat_history) ? req.chat_history : [],
    question,
    owner,
    pr_context: {
      owner,
      repos,
      total_found: allPrs.length,
      selected_count: selected.length,
      query_terms: queryTerms,
      prs: selected,
      commit_text_hits: commitHits,
      code_snippets: codeSnippets,
      fastroute_modelo_dados: fastrouteModeloDados
    }
  }
}];

const toStr = (v) => String(v ?? '').trim();
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const text = toStr($json.text || $json.response?.text || '');
if (!text) throw new Error('[Build PR Chat Reply] LLM retornou texto vazio.');

const fromNormalize = (() => {
  try { return $items('Normalize Chat Input', 0, 0)[0]?.json || {}; } catch (_e) { return {}; }
})();
const fromFetch = (() => {
  try { return $items('Fetch PR + Code Context (PR QA)', 0, 0)[0]?.json || {}; } catch (_e) { return {}; }
})();

const sessionId = toStr($json.session_id || fromFetch.session_id || fromNormalize.session_id || 'default');
const route = toStr($json.route || fromFetch.route || fromNormalize.route || 'pr_qa');
const precheckOriginal = toStr(fromFetch.precheck_original_message || fromNormalize.precheck_original_message || fromFetch.question || fromNormalize.question || '');
const qaQuestion = toStr(fromFetch.question || fromNormalize.question || '');

const normalizeStatus = (s) => {
  const v = toStr(s)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
    .replace(/\s+/g, '_')
    .replace(/-/g, '_');

  if (v === 'SIM') return 'SIM';
  if (v === 'PARCIAL') return 'PARCIAL';
  if (v === 'NAO' || v === 'N') return 'NAO';
  if (v === 'SEM_EVIDENCIA' || v === 'SEMEVIDENCIA') return 'SEM_EVIDENCIA';
  return '';
};

const tryParseJsonStatus = (raw) => {
  const txt = toStr(raw);
  const candidates = [txt];
  const fenced = txt.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced && fenced[1]) candidates.push(toStr(fenced[1]));

  for (const c of candidates) {
    try {
      const obj = JSON.parse(c);
      if (obj && typeof obj === 'object' && 'status' in obj) {
        const st = normalizeStatus(obj.status);
        if (st) return st;
      }
    } catch (_e) {}
  }
  return '';
};

const parseStatus = (raw) => {
  const txt = toStr(raw);
  const jsonStatus = tryParseJsonStatus(txt);
  if (jsonStatus) return jsonStatus;

  const patterns = [
    /(?:^|\n)\s*[-*]?\s*[*_`"]?status[*_`"]?\s*[:=]\s*[*_`"]?(SIM|PARCIAL|NAO|NÃO|SEM[ _-]?EVIDENCIA)\b/i,
    /"status"\s*:\s*"(SIM|PARCIAL|NAO|NÃO|SEM[ _-]?EVIDENCIA)"/i,
    /\bstatus\b[^\n]{0,80}\b(SIM|PARCIAL|NAO|NÃO|SEM[ _-]?EVIDENCIA)\b/i,
  ];

  for (const re of patterns) {
    const m = txt.match(re);
    if (m && m[1]) {
      const st = normalizeStatus(m[1]);
      if (st) return st;
    }
  }
  return '';
};

let output = text;

const getStore = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (this && typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  throw new Error('[Build PR Chat Reply] static data indisponivel no Code node.');
};

const store = getStore();
if (!store.chatMemory) store.chatMemory = {};
if (!store.chatModes) store.chatModes = {};
if (!store.impactDrafts) store.impactDrafts = {};
if (!store.impactPrecheck) store.impactPrecheck = {};
if (!store.pendingImpactProceed) store.pendingImpactProceed = {};
if (!store.lastSuggestedImpactPayload) store.lastSuggestedImpactPayload = {};
if (!store.qaCache) store.qaCache = {};
if (!store.precheckCache) store.precheckCache = {};
if (!Array.isArray(store.chatMemory[sessionId])) store.chatMemory[sessionId] = [];
if (!('chatModeGlobal' in store)) store.chatModeGlobal = '';
if (!('impactDraftGlobal' in store)) store.impactDraftGlobal = null;
if (!('impactPrecheckGlobal' in store)) store.impactPrecheckGlobal = { done: false, checked_at: null, status: '' };
if (!('pendingImpactProceedGlobal' in store)) store.pendingImpactProceedGlobal = { awaiting: false };
if (!('lastSuggestedImpactPayloadGlobal' in store)) store.lastSuggestedImpactPayloadGlobal = null;

if (route === 'pr_qa_precheck') {
  let status = parseStatus(text);
  const statusFromFallback = !status;
  if (!status) status = 'SEM_EVIDENCIA';

  const precheckPayload = { done: true, status, checked_at: new Date().toISOString() };
  store.impactPrecheck[sessionId] = precheckPayload;
  store.impactPrecheckGlobal = precheckPayload;

  const suggestedPayload = {
    problema: precheckOriginal || 'Necessidade identificada via analise de PRs',
    mudanca: [
      'Prosseguir com implementacao/correcao da necessidade com base na analise de PRs.',
      'Status da analise: ' + status + '.',
      precheckOriginal ? ('Necessidade original: ' + precheckOriginal) : ''
    ].filter(Boolean).join(' '),
    evidencias: [
      'Resultado da analise de PRs: status=' + status + '.',
      text
    ].join('\n\n'),
    restricoes: 'Manter compatibilidade com PRs existentes e evitar regressao funcional.'
  };

  const needKey = norm(precheckOriginal || qaQuestion || '');
  if (needKey) {
    store.precheckCache[needKey] = {
      status,
      analysis_text: text,
      suggested_payload: suggestedPayload,
      updated_at: new Date().toISOString()
    };
  }

  if (status === 'SIM') {
    delete store.impactDrafts[sessionId];
    store.impactDraftGlobal = null;
    delete store.pendingImpactProceed[sessionId];
    store.pendingImpactProceedGlobal = { awaiting: false };
    delete store.lastSuggestedImpactPayload[sessionId];
    store.lastSuggestedImpactPayloadGlobal = null;
    delete store.chatModes[sessionId];
    store.chatModeGlobal = '';

    output = [
      'Verificacao previa concluida: a necessidade ja existe (status SIM).',
      'Nao vou prosseguir com Impact Analysis.',
      '',
      text,
      '',
      'Se quiser iniciar uma nova solicitacao, envie /menu.'
    ].join('\n');
  } else {
    store.lastSuggestedImpactPayload[sessionId] = suggestedPayload;
    store.lastSuggestedImpactPayloadGlobal = suggestedPayload;

    const pending = {
      awaiting: true,
      status,
      analysis_text: text,
      suggested_payload: suggestedPayload,
      created_at: new Date().toISOString()
    };

    store.pendingImpactProceed[sessionId] = pending;
    store.pendingImpactProceedGlobal = pending;

    const header = statusFromFallback
      ? 'Resultado da analise de PRs: SEM_EVIDENCIA (fallback aplicado: Status nao identificado no retorno do LLM).'
      : 'Resultado da analise de PRs: ' + status + '.';

    output = [
      header,
      '',
      text,
      '',
      'Deseja prosseguir com a implementacao?',
      'Se responder SIM, vou acionar o fluxo Impact Analysis com Impact Inputs preenchidos a partir desta analise.',
      'Responda apenas: SIM ou NAO.'
    ].join('\n');
  }
}

if (route === 'pr_qa') {
  const qKey = norm(qaQuestion);
  if (qKey) {
    store.qaCache[qKey] = {
      output: text,
      updated_at: new Date().toISOString()
    };
  }
}

store.chatMemory[sessionId].push({ role: 'assistant', content: output, at: new Date().toISOString() });
if (store.chatMemory[sessionId].length > 40) {
  store.chatMemory[sessionId] = store.chatMemory[sessionId].slice(-40);
}

return [{ json: { output } }];

const toStr = (v) => String(v ?? '').trim();

const rawText = toStr($json.text || $json.response?.text || '');
if (!rawText) throw new Error('[Parse Impact Intake Response] LLM retornou texto vazio.');

const tryParse = (txt) => {
  const candidates = [txt];
  const fenced = txt.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced && fenced[1]) candidates.push(toStr(fenced[1]));
  for (const c of candidates) {
    try {
      return JSON.parse(c);
    } catch (_e) {}
  }
  throw new Error('[Parse Impact Intake Response] JSON invalido no retorno do LLM.');
};

const parsed = tryParse(rawText);
const updates = parsed && typeof parsed === 'object' ? (parsed.updates || {}) : {};

const fromNormalize = (() => {
  try { return $items('Normalize Chat Input', 0, 0)[0]?.json || {}; } catch (_e) { return {}; }
})();

const sessionId = toStr(fromNormalize.session_id || 'default');
const getStore = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (this && typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  throw new Error('[Parse Impact Intake Response] static data indisponivel no Code node.');
};

const store = getStore();
if (!store.impactIntakeState) store.impactIntakeState = {};
if (!store.selectedOption) store.selectedOption = {};

const base = store.impactIntakeState[sessionId] || {
  problema: '',
  mudanca: '',
  evidencias: '',
  restricoes: '',
  status: '',
  diagnostico: '',
  evidencias_lista: []
};

const pickStr = (a, b) => {
  const x = toStr(a);
  if (x) return x;
  return toStr(b);
};

base.problema = pickStr(updates.problema, parsed.problema || base.problema);
base.mudanca = pickStr(updates.mudanca, parsed.mudanca || base.mudanca);
base.evidencias = pickStr(updates.evidencias, parsed.evidencias || base.evidencias);
base.restricoes = pickStr(updates.restricoes, parsed.restricoes || base.restricoes);
base.status = pickStr(updates.status, parsed.status || base.status);
base.diagnostico = pickStr(updates.diagnostico, parsed.diagnostico || base.diagnostico);

const listA = Array.isArray(base.evidencias_lista) ? base.evidencias_lista : [];
const listB = Array.isArray(updates.evidencias_lista) ? updates.evidencias_lista : (Array.isArray(parsed.evidencias_lista) ? parsed.evidencias_lista : []);
base.evidencias_lista = [...new Set([...listA, ...listB].map((x) => toStr(x)).filter(Boolean))];

store.impactIntakeState[sessionId] = base;

const required = ['problema', 'mudanca', 'evidencias', 'restricoes'];
const missing = required.filter((k) => !toStr(base[k]));
const complete = missing.length === 0;

if (complete) {
  delete store.selectedOption[sessionId];
  delete store.impactIntakeState[sessionId];

  return [{
    json: {
      route: 'impact_run_manual',
      session_id: sessionId,
      impact_payload: {
        problema: toStr(base.problema),
        mudanca: toStr(base.mudanca),
        evidencias: toStr(base.evidencias),
        restricoes: toStr(base.restricoes),
      },
      status: toStr(base.status),
      diagnostico: toStr(base.diagnostico),
      evidencias_lista: base.evidencias_lista,
      output: 'Dados coletados. Vou disparar o Impact Analysis agora.'
    }
  }];
}

const firstMissing = missing[0] || 'problema';
const examples = {
  problema: 'Exemplo de problema: Alto indice de insucesso na entrega por ausencia do morador.',
  mudanca: 'Exemplo de mudanca: Enviar SMS D-1 com opcoes de confirmacao/reagendamento/endereco alternativo.',
  evidencias: 'Exemplo de evidencias: SMS enviado e resposta recebida/persistida com timestamp.',
  restricoes: 'Exemplo de restricoes: Sem aumento de custo por mensagem acima de 10%.',
};

const llmReply = toStr(parsed.reply || '');
const output = llmReply || [
  'Para continuar, informe o campo: ' + firstMissing,
  examples[firstMissing] || ''
].filter(Boolean).join('\n');

return [{
  json: {
    route: 'impact_collect_question',
    session_id: sessionId,
    output,
    draft: base,
  }
}];
